  1	import * as React from 'react';
  2	import { useTranslation } from 'react-i18next';
  3	import {
  4	  Alert,
  5	  AlertGroup,
  6	  EmptyState,
  7	  EmptyStateIcon,
  8	  EmptyStateBody,
  9	  Title,
 10	} from '@patternfly/react-core';
 11	import {
 12	  K8sResourceKind,
 13	  ResourceLink,
 14	  useK8sWatchResources,
 15	  VirtualizedTable,
 16	  TableData,
 17	  RowProps,
 18	  TableColumn,
 19	  WatchK8sResource,
 20	} from '@openshift-console/dynamic-plugin-sdk';
 21	import { SearchIcon } from '@patternfly/react-icons';
 22	import { getStatusLabel } from '../utils/statusLabel';
 23	
 24	type AssociatedResourceListProps = {
 25	  resource: K8sResourceKind;
 26	};
 27	
 28	const AssociatedResourceList: React.FC<AssociatedResourceListProps> = ({ resource }) => {
 29	  const { t } = useTranslation('plugin__kuadrant-console-plugin');
 30	
 31	  // TODO: dynamic?
 32	  const associatedResources: { [key: string]: WatchK8sResource } = {
 33	    RateLimitPolicy: {
 34	      groupVersionKind: { group: 'kuadrant.io', version: 'v1', kind: 'RateLimitPolicy' },
 35	      isList: true,
 36	      namespace: resource.metadata.namespace,
 37	    },
 38	    AuthPolicy: {
 39	      groupVersionKind: { group: 'kuadrant.io', version: 'v1', kind: 'AuthPolicy' },
 40	      isList: true,
 41	      namespace: resource.metadata.namespace,
 42	    },
 43	    DNSPolicy: {
 44	      groupVersionKind: { group: 'kuadrant.io', version: 'v1', kind: 'DNSPolicy' },
 45	      isList: true,
 46	      namespace: resource.metadata.namespace,
 47	    },
 48	    TLSPolicy: {
 49	      groupVersionKind: { group: 'kuadrant.io', version: 'v1', kind: 'TLSPolicy' },
 50	      isList: true,
 51	      namespace: resource.metadata.namespace,
 52	    },
 53	  };
 54	
 55	  const watchedResources = useK8sWatchResources<{ [key: string]: K8sResourceKind[] }>(
 56	    associatedResources,
 57	  );
 58	
 59	  const resourceGroup = resource.apiVersion.includes('/') ? resource.apiVersion.split('/')[0] : '';
 60	
 61	  const allAssociatedResources = React.useMemo(() => {
 62	    let resourcesArray: K8sResourceKind[] = [];
 63	    Object.values(watchedResources).forEach((res) => {
 64	      if (res.loaded && !res.loadError && res.data) {
 65	        const matchingItems = (res.data as K8sResourceKind[]).filter((item) => {
 66	          const targetRef = item.spec?.targetRef;
 67	          if (!targetRef) return false;
 68	          return (
 69	            targetRef.group === resourceGroup &&
 70	            targetRef.kind === resource.kind &&
 71	            targetRef.name === resource.metadata.name
 72	          );
 73	        });
 74	        resourcesArray = resourcesArray.concat(matchingItems);
 75	      }
 76	    });
 77	    return resourcesArray;
 78	  }, [watchedResources, resource, resourceGroup]);
 79	
 80	  const columns: TableColumn<K8sResourceKind>[] = [
 81	    {
 82	      title: t('plugin__kuadrant-console-plugin~Name'),
 83	      id: 'name',
 84	      sort: 'metadata.name',
 85	    },
 86	    {
 87	      title: t('plugin__kuadrant-console-plugin~Type'),
 88	      id: 'type',
 89	      sort: 'kind',
 90	    },
 91	    {
 92	      title: t('plugin__kuadrant-console-plugin~Namespace'),
 93	      id: 'namespace',
 94	      sort: 'metadata.namespace',
 95	    },
 96	    {
 97	      title: t('plugin__kuadrant-console-plugin~Status'),
 98	      id: 'status',
 99	    },
100	  ];
101	
102	  const AssociatedResourceRow: React.FC<RowProps<K8sResourceKind>> = ({ obj, activeColumnIDs }) => {
103	    const [group, version] = obj.apiVersion.includes('/')
104	      ? obj.apiVersion.split('/')
105	      : ['', obj.apiVersion];
106	    return (
107	      <>
108	        {columns.map((column) => {
109	          switch (column.id) {
110	            case 'name':
111	              return (
112	                <TableData key={column.id} id={column.id} activeColumnIDs={activeColumnIDs}>
113	                  <ResourceLink
114	                    groupVersionKind={{ group, version, kind: obj.kind }}
115	                    name={obj.metadata.name}
116	                    namespace={obj.metadata.namespace}
117	                  />
118	                </TableData>
119	              );
120	            case 'type':
121	              return (
122	                <TableData key={column.id} id={column.id} activeColumnIDs={activeColumnIDs}>
123	                  {obj.kind}
124	                </TableData>
125	              );
126	            case 'namespace':
127	              return (
128	                <TableData key={column.id} id={column.id} activeColumnIDs={activeColumnIDs}>
129	                  {obj.metadata.namespace || '-'}
130	                </TableData>
131	              );
132	            case 'status':
133	              return (
134	                <TableData key={column.id} id={column.id} activeColumnIDs={activeColumnIDs}>
135	                  {getStatusLabel(obj)}
136	                </TableData>
137	              );
138	            default:
139	              return null;
140	          }
141	        })}
142	      </>
143	    );
144	  };
145	
146	  const allLoaded = Object.values(watchedResources).every((res) => res.loaded);
147	  const loadErrors = Object.values(watchedResources)
148	    .filter((res) => res.loadError)
149	    .map((res) => res.loadError);
150	  const combinedLoadError =
151	    loadErrors.length > 0 ? new Error(loadErrors.map((err) => err.message).join('; ')) : null;
152	
153	  return (
154	    <>
155	      {combinedLoadError && (
156	        <AlertGroup>
157	          <Alert title="Error loading associated resources" variant="danger" isInline>
158	            {combinedLoadError.message}
159	          </Alert>
160	        </AlertGroup>
161	      )}
162	      {allAssociatedResources.length === 0 && allLoaded ? (
163	        <EmptyState>
164	          <EmptyStateIcon icon={SearchIcon} />
165	          <Title headingLevel="h4" size="lg">
166	            {t('No associated resources found')}
167	          </Title>
168	          <EmptyStateBody>{t('No associated policies found')}</EmptyStateBody>
169	        </EmptyState>
170	      ) : (
171	        <VirtualizedTable<K8sResourceKind>
172	          data={allAssociatedResources}
173	          unfilteredData={allAssociatedResources}
174	          loaded={allLoaded}
175	          loadError={combinedLoadError}
176	          columns={columns}
177	          Row={AssociatedResourceRow}
178	        />
179	      )}
180	    </>
181	  );
182	};
183	
184	export default AssociatedResourceList;

